import os
import sys
import redis

BANNER = """\
Dynamic Redis Lua Executor
- Reads Lua script from stdin until EOF
- Passes user-provided KEYS and ARGS directly into EVAL
"""

def _parse_int(name, value, default=None):
    if value is None:
        return default
    try:
        return int(value)
    except Exception:
        raise SystemExit(f"Invalid integer for {name}: {value!r}")

def _split_csv(value):
    if value is None or value.strip() == "":
        return []
    return [v for v in (x.strip() for x in value.split(",")) if v != ""]

def main():
    host = os.getenv("REDIS_HOST", "127.0.0.1")
    port = _parse_int("REDIS_PORT", os.getenv("REDIS_PORT", "6379"), 6379)
    db = _parse_int("REDIS_DB", os.getenv("REDIS_DB", "0"), 0)
    password = os.getenv("REDIS_PASSWORD", None)

    keys = _split_csv(os.getenv("REDIS_LUA_KEYS", ""))
    args = _split_csv(os.getenv("REDIS_LUA_ARGS", ""))

    print(BANNER, file=sys.stderr)
    print("Env vars:", file=sys.stderr)
    print(f"  REDIS_HOST={host}", file=sys.stderr)
    print(f"  REDIS_PORT={port}", file=sys.stderr)
    print(f"  REDIS_DB={db}", file=sys.stderr)
    print(f"  REDIS_PASSWORD={'(set)' if password else '(not set)'}", file=sys.stderr)
    print(f"  REDIS_LUA_KEYS={keys}", file=sys.stderr)
